import React, { useState } from 'react';
import { loginAdmin } from '../../services/api';
import { FaUser, FaLock, FaArrowRight } from 'react-icons/fa';

const LoginPage = ({ onLogin }) => {
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const response = await loginAdmin(username, password);
      if (response.data.access_token) {
        onLogin(response.data.access_token);
      }
    } catch (err) {
      setError('Invalid credentials! Use varshini / varshu');
    }
    setLoading(false);
  };

  return (
    <div style={{
      minHeight: '100vh',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      padding: '20px'
    }}>
      <div style={{
        display: 'flex',
        maxWidth: '1000px',
        width: '100%',
        background: 'white',
        borderRadius: '20px',
        overflow: 'hidden',
        boxShadow: '0 20px 60px rgba(0,0,0,0.3)',
        minHeight: '550px'
      }}>
        {/* Left Side - Brand Section */}
        <div style={{
          flex: 1,
          background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
          padding: '50px 40px',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          color: 'white'
        }}>
          <div>
            <div style={{
              fontSize: '28px',
              fontWeight: 'bold',
              marginBottom: '10px',
              lineHeight: '1.2'
            }}>
              AI-Resume
              <br />
              Screening System
            </div>

            <div style={{
              height: '4px',
              width: '60px',
              background: 'rgba(255,255,255,0.5)',
              margin: '30px 0',
              borderRadius: '2px'
            }}></div>

            <h1 style={{
              fontSize: '36px',
              fontWeight: 'bold',
              marginBottom: '20px',
              lineHeight: '1.3'
            }}>
              AI-Powered Resume Screening Made Simple
            </h1>

            <p style={{
              fontSize: '16px',
              opacity: 0.95,
              lineHeight: '1.6'
            }}>
              Analyze, rank and hire the best candidates faster with the power of AI.
            </p>
          </div>
        </div>

        {/* Right Side - Login Form */}
        <div style={{
          flex: 1,
          padding: '50px 40px',
          display: 'flex',
          flexDirection: 'column',
          justifyContent: 'center',
          background: 'white'
        }}>
          <div>
            <h2 style={{
              fontSize: '28px',
              color: '#333',
              marginBottom: '10px',
              fontWeight: 'bold'
            }}>
              Admin Login
            </h2>
            <p style={{
              color: '#666',
              fontSize: '15px',
              marginBottom: '30px'
            }}>
              Welcome back! Please login to continue.
            </p>

            {error && (
              <div style={{
                background: '#fee',
                color: '#c33',
                padding: '12px',
                borderRadius: '8px',
                marginBottom: '20px',
                fontSize: '14px',
                border: '1px solid #fcc'
              }}>
                {error}
              </div>
            )}

            <form onSubmit={handleSubmit}>
              {/* Username Field */}
              <div style={{
                marginBottom: '25px'
              }}>
                <label style={{
                  display: 'block',
                  marginBottom: '8px',
                  color: '#555',
                  fontWeight: '500',
                  fontSize: '14px'
                }}>
                  Username
                </label>
                <div style={{
                  position: 'relative'
                }}>
                  <FaUser style={{
                    position: 'absolute',
                    left: '15px',
                    top: '50%',
                    transform: 'translateY(-50%)',
                    color: '#999',
                    fontSize: '16px'
                  }} />
                  <input
                    type="text"
                    placeholder="Enter your username"
                    value={username}
                    onChange={(e) => setUsername(e.target.value)}
                    style={{
                      width: '100%',
                      padding: '14px 15px 14px 45px',
                      border: '1px solid #e0e0e0',
                      borderRadius: '10px',
                      fontSize: '15px',
                      outline: 'none',
                      transition: 'all 0.3s'
                    }}
                    required
                    disabled={loading}
                    onFocus={(e) => e.target.style.borderColor = '#667eea'}
                    onBlur={(e) => e.target.style.borderColor = '#e0e0e0'}
                  />
                </div>
              </div>

              {/* Password Field */}
              <div style={{
                marginBottom: '30px'
              }}>
                <label style={{
                  display: 'block',
                  marginBottom: '8px',
                  color: '#555',
                  fontWeight: '500',
                  fontSize: '14px'
                }}>
                  Password
                </label>
                <div style={{
                  position: 'relative'
                }}>
                  <FaLock style={{
                    position: 'absolute',
                    left: '15px',
                    top: '50%',
                    transform: 'translateY(-50%)',
                    color: '#999',
                    fontSize: '16px'
                  }} />
                  <input
                    type="password"
                    placeholder="Enter your password"
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    style={{
                      width: '100%',
                      padding: '14px 15px 14px 45px',
                      border: '1px solid #e0e0e0',
                      borderRadius: '10px',
                      fontSize: '15px',
                      outline: 'none',
                      transition: 'all 0.3s'
                    }}
                    required
                    disabled={loading}
                    onFocus={(e) => e.target.style.borderColor = '#667eea'}
                    onBlur={(e) => e.target.style.borderColor = '#e0e0e0'}
                  />
                </div>
              </div>

              {/* Login Button */}
              <button
                type="submit"
                disabled={loading}
                style={{
                  width: '100%',
                  padding: '14px',
                  background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                  color: 'white',
                  border: 'none',
                  borderRadius: '10px',
                  fontSize: '16px',
                  fontWeight: '600',
                  cursor: loading ? 'not-allowed' : 'pointer',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  gap: '10px',
                  transition: 'transform 0.2s'
                }}
                onMouseEnter={(e) => e.target.style.transform = 'translateY(-2px)'}
                onMouseLeave={(e) => e.target.style.transform = 'translateY(0)'}
              >
                {loading ? 'Logging in...' : 'Login'}
                {!loading && <FaArrowRight size={14} />}
              </button>

              {/* Demo Credentials */}
              <div style={{
                marginTop: '30px',
                padding: '12px',
                background: '#f0f0f0',
                borderRadius: '8px',
                textAlign: 'center'
              }}>
                <p style={{
                  fontSize: '12px',
                  color: '#666',
                  margin: 0
                }}>
                  </p>
              </div>
            </form>
          </div>
        </div>
      </div>

      {/* Footer */}
      <div style={{
        position: 'fixed',
        bottom: '20px',
        left: '0',
        right: '0',
        textAlign: 'center',
        fontSize: '12px',
        color: 'rgba(255,255,255,0.7)'
      }}>
        © 2024 AI Resume Screening System. All rights reserved.
      </div>
    </div>
  );
};

export default LoginPage;
